#include <iostream>
#include <vector>
#include <iomanip>
#include <algorithm>
#include <cmath>

using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    vector<double> a(n);
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }

    int min_idx = 0, max_idx = 0;
    for (int i = 1; i < n; i++) {
        if (a[i] < a[min_idx]) min_idx = i;
        if (a[i] > a[max_idx]) max_idx = i;
    }

    swap(a[min_idx], a[max_idx]);

    cout << fixed << setprecision(2);
    for (int i = 0; i < n; i++) {
        if (i > 0) cout << ' ';
        cout << a[i];
    }
    cout << '\n';

    return 0;
}
